// Demonstrates the TypeScript SDK's cache-first and fail-open behavior using
// the ranking JSON generated by rank_from_csv.py. No cache credentials.
import assert from 'node:assert/strict';
import { readFile } from 'node:fs/promises';

// @ts-ignore – dist is built before running this demo; see client/typescript/
import { Selector } from '../../client/typescript/dist/index.mjs';

const modelId = 'black-forest-labs/flux-schnell';
const region = 'us';
const fallback = ['provider_a', 'provider_b', 'provider_c'];

class MemoryCache {
  /**
   * @param {string | null} payload
   */
  constructor(payload) {
    /** @type {string | null} */
    this.payload = payload;
  }

  /**
   * @returns {Promise<string | null>}
   */
  async get() {
    return this.payload;
  }
}

const rankingTemplate = await readFile(
  new URL('./ranking.expected.json', import.meta.url),
  'utf8',
);
const rankingJson = rankingTemplate.replace(
  '"<generated-at-runtime>"',
  JSON.stringify(new Date().toISOString()),
);

const cachedSelector = new Selector({ cache: new MemoryCache(rankingJson) });
const cachedOrder = await cachedSelector.rank({ modelId, region, fallback });

const malformedSelector = new Selector({ cache: new MemoryCache('{not-json') });
const malformedOrder = await malformedSelector.rank({ modelId, region, fallback });

const missingSelector = new Selector({ cache: new MemoryCache(null) });
const missingOrder = await missingSelector.rank({ modelId, region, fallback });

assert.deepEqual(cachedOrder, ['provider_b', 'provider_c', 'provider_a']);
assert.equal(cachedSelector.lastDecision?.source, 'cached-ranking');
assert.deepEqual(malformedOrder, fallback);
assert.equal(malformedSelector.lastDecision?.source, 'fallback');
assert.deepEqual(missingOrder, fallback);
assert.equal(missingSelector.lastDecision?.source, 'fallback');

console.log(
  JSON.stringify(
    {
      cached: {
        order: cachedOrder,
        source: cachedSelector.lastDecision?.source,
      },
      malformed: {
        order: malformedOrder,
        source: malformedSelector.lastDecision?.source,
      },
      missing: {
        order: missingOrder,
        source: missingSelector.lastDecision?.source,
      },
    },
    null,
    2,
  ),
);
